sql:
SELECT portfolio_id, average_return, total_exec_time
FROM portfolio_performance
ORDER BY total_exec_time DESC;

SELECT MIN(max_return) AS min_max_return, 
       MAX(max_return) AS max_max_return
FROM portfolio_performance;

SELECT MAX(max_return) AS max_max_return
FROM portfolio_performance
WHERE mean_kl < 0.05;

SELECT portfolio_id, AVG(accuracy) AS average_accuracy
FROM model_performance
GROUP BY portfolio_id;

SELECT AVG(total_exec_time) AS overall_average_exec_time
FROM portfolio_performance
WHERE created_at BETWEEN '2023-01-01' AND '2023-12-31';

WITH AvgReturnCTE AS (
    SELECT AVG(average_return) AS garden_avg_return FROM portfolio_performance
)
SELECT average_return
FROM portfolio_performance
WHERE min_return > 0 AND average_return > (SELECT garden_avg_return FROM AvgReturnCTE);

SELECT max_return
FROM portfolio_performance
ORDER BY max_return DESC;

SELECT AVG(average_return) AS average_high_exec_time_return
FROM portfolio_performance
WHERE total_exec_time = (
    SELECT MAX(total_exec_time)
    FROM portfolio_performance
);

SELECT strategy_name 
FROM investment_strategies 
WHERE risk_level = 'High';

SELECT portfolio_id, average_return AS typical_earnings
FROM portfolio_performance
WHERE mean_kl BETWEEN 0.1 AND 0.5;

SELECT average_return
FROM portfolio_performance
WHERE portfolio_id = 1;

SELECT portfolio_id, max_return
FROM portfolio_performance
ORDER BY max_return DESC;

external_knowledge:
- The term 'promising' refers to a portfolio that has a high 'max_return' and meets the specified criteria; 
- 'Low mean KL divergence' and 'explained variance' indicate better model accuracy and reliability;
- 'Standard deviation of returns under 1000' suggests relatively low risk.

sql:
SELECT AVG(pp.average_return) AS average_high_return_portfolios
FROM portfolio_performance pp
WHERE pp.max_return > 1500;

SELECT portfolio_id, MAX(max_return) AS max_return
FROM portfolio_performance
GROUP BY portfolio_id;

SELECT max_return
FROM portfolio_performance
WHERE portfolio_id = 1;
